def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio > 1:
            score = 2000 + 20 * (ratio - 1)**3
            if ratio > 2:
                score += 500 * (ratio - 2)
        else:
            if ratio > 0.9:
                score += 100 * ratio
                if capacity < 20:
                    score += 30
                elif capacity > 80:
                    score -= 10
            elif ratio > 0.7:
                score += 60 * ratio
                if capacity < 15:
                    score += 20
            elif ratio > 0.4:
                score += 25 * ratio
                if capacity > 50:
                    score -= 15
            else:
                score += 5 * ratio
                if capacity < 5:
                    score += 10
        if i % 3 == 0:
            score *= 1.2
            for j in range(i+1, min(i+4, len(bins))):
                neighbor_capacity = bins[j]
                if neighbor_capacity > capacity:
                    score -= 5
                else:
                    score += 5
        elif i % 3 == 1:
            score *= 0.8
            if capacity % 2 == 0:
                score += 10
            else:
                score -= 10
        else:
            score *= 1.0 + ((i % 5) * 0.05)
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) == 0:
        min_priority = 0
    else:
        min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 150
    adjusted_priorities = np.copy(priorities)
    for _ in range(3):
        for i in range(1, len(priorities)-1):
            neighbors_avg = (priorities[i-1] + priorities[i+1]) / 2
            adjusted_priorities[i] = (priorities[i] + neighbors_avg) / 2
        priorities = np.copy(adjusted_priorities)
    return priorities
